INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, 24, 24001, 102301, 10046, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 2, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 401, 0.0, "アヤネ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2.21, 24, 24002, 102301, 10046, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 1, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 402, 0.0, "アヤネ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, 24, 24003, 102301, 10046, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 2, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 403, 0.0, "アヤネ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (1.99, 24, 24004, 192201, 10046, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 2, 0.0, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 701, 0.0, "アサヒ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2.21, 24, 24005, 192201, 10046, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 1, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 702, 0.0, "アサヒ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (3.33, 24, 24006, 192201, 10046, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 2, 0.0, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 703, 0.0, "アサヒ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, 24, 24007, 192301, 10046, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 2, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 801, 0.0, "部員３");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2.68, 24, 24008, 192301, 10046, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 1, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 802, 0.0, "部員３");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, 24, 24009, 192301, 10046, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 2, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 803, 0.0, "部員３");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, 24, 24010, 192501, 10046, "やった！", 1, 0.0, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 501, 0.0, "");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, 24, 24011, 192501, 10046, "勝ったよ！", 1, 0.0, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 502, 0.0, "");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, 24, 24012, 192501, 10046, "いい調子！", 1, 0.0, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 503, 0.0, "");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (5.33, 24, 24013, 113501, 10046, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 6, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 111, 0.0, "ミサト");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (6.85, 24, 24014, 113501, 10046, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 1, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 112, 0.0, "ミサト");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (3.0, 24, 24015, 113501, 10046, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 1, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 113, 0.0, "ミサト");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (6.11, 24, 24016, 192401, 10046, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 1, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 611, 0.0, "ダイチ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (6.75, 24, 24017, 192401, 10046, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 1, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 612, 0.0, "ダイチ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, 24, 24018, 192401, 10046, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 2, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 613, 0.0, "ダイチ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (4.52, 24, 24019, 113401, 10046, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 2, 0.0, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 211, 0.0, "ハツネ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (3.89, 24, 24020, 113401, 10046, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 2, 0.0, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 212, 0.0, "ハツネ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (13.49, 24, 24021, 113401, 10046, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 1, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 213, 0.0, "ハツネ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (3.17, 24, 24022, 106501, 10046, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 1, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 311, 0.0, "カヤ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (4.42, 24, 24023, 106501, 10046, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 1, 0.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 312, 0.0, "カヤ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (2.89, 24, 24024, 106501, 10046, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 6, 0.0, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 313, 0.0, "カヤ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (3.71, 24, 24025, 102301, 10046, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 4, 0.0, "2030/12/17 14:59:59", 3, "2020/07/31 12:00:00", 421, 0.0, "アヤネ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (5.1, 24, 24026, 192201, 10046, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 2, 0.0, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 721, 0.0, "アサヒ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (4.34, 24, 24027, 192301, 10046, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 1, 0.0, "2030/12/17 14:59:59", 3, "2020/07/31 12:00:00", 821, 0.0, "部員３");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, 24, 24028, 192501, 10046, "いい勝負だったよ\nまたやろうね", 1, 0.0, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 521, 0.0, "");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (5.62, 24, 24029, 113501, 10046, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 1, -360.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 101, 0.0, "ミサト");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (9.58, 24, 24030, 113501, 10046, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 1, -360.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 102, 0.0, "ミサト");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, 24, 24031, 113501, 10046, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 2, -360.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 103, 0.0, "ミサト");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (9.13, 24, 24032, 113501, 10046, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 2, -360.0, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 104, 0.0, "ミサト");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (8.27, 24, 24033, 113501, 10046, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 1, -360.0, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 105, 0.0, "ミサト");
